const et = ctx.helpers.eventPrimaryQuestionType(ctx);

const closes = ctx.underlying.klines.map((k) => k.close);
const rsi14 = ctx.helpers.rsi(closes, 14);
const emaFast = ctx.helpers.emaArray(closes, 12).at(-1);
const emaSlow = ctx.helpers.emaArray(closes, 26).at(-1);
const macroTrend = emaFast > emaSlow ? 1 : -1;
const volRatio = ctx.helpers.volRatio(ctx, "1h", "24h");

const logit   = (p) => Math.log(Math.min(Math.max(p, 1e-6), 1 - 1e-6) / (1 - Math.min(Math.max(p, 1e-6), 1 - 1e-6)));
const sigmoid = (x) => 1 / (1 + Math.exp(-x));

const THRESHOLD = 0.04;

const baseYesProb = (mCtx, questionType) => {
  switch (questionType) {
    case "above":  return ctx.helpers.bsAbove(mCtx);
    case "below":  return 1 - ctx.helpers.bsAbove(mCtx);
    case "hit":    return ctx.helpers.bsOneTouch(mCtx);
    case "range":  return ctx.helpers.bsRange(mCtx);
    case "firstHit": return null;
    default: throw new Error("unsupported questionType: " + questionType);
  }
};

return ctx.markets.map((market) => {
  try {
    if (market.closed || market.hoursToExpiry < 0) {
      return { question: market.question, questionType: market.questionType, decision: "hold", reason: "closed or expired" };
    }

    const mCtx = { market, underlying: ctx.underlying, timing: ctx.timing };
    let probs;

    if (market.questionType === "firstHit") {
      probs = ctx.helpers.firstHitProbabilities(mCtx, { seed: 42 });
    } else if (market.questionType === "unknown" || market.strike === null) {
      return { question: market.question, questionType: market.questionType, decision: "hold", reason: "unknown type or null strike" };
    } else {
      const base = baseYesProb(mCtx, market.questionType);
      const dist = ctx.helpers.distanceToStrike(mCtx);
      const rsiShift = (rsi14 - 50) / 200;
      const trendShift = macroTrend * 0.04;
      const volShift = (volRatio > 1.2) ? 0.02 : (volRatio < 0.8) ? -0.02 : 0;
      const distShift = market.questionType === "hit"
        ? Math.sign(-dist) * Math.min(Math.abs(dist) * 0.1, 0.03)
        : 0;
      const shift = rsiShift + trendShift + volShift + distShift;
      const yesAdj = sigmoid(logit(base) + shift);
      probs = ctx.helpers.binaryProbsFromYesProb(mCtx, yesAdj);
    }

    const edges = ctx.helpers.edgeFromProbs(probs, mCtx);
    const best = edges[0].edge >= edges[1].edge ? edges[0] : edges[1];

    if (best.edge < THRESHOLD) {
      return {
        question: market.question,
        questionType: market.questionType,
        expiryDate: market.expiryDate,
        probs,
        decision: "hold",
        edge: +best.edge.toFixed(4),
      };
    }

    return {
      question: market.question,
      questionType: market.questionType,
      expiryDate: market.expiryDate,
      probs,
      decision: "buy",
      side: best.label,
      fairPrice: +best.fairPrice.toFixed(4),
      marketPrice: +best.marketPrice.toFixed(4),
      edge: +best.edge.toFixed(4),
    };
  } catch (err) {
    return { question: market.question, questionType: market.questionType, decision: "hold", reason: String(err) };
  }
});
